class Board:
    def __init__(self):
        self._pieces = {}
        self.initialize_board()

    def initialize_board(self):
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    if row < 3:
                        self._pieces[(row, col)] = Piece("black")
                    elif row > 4:
                        self._pieces[(row, col)] = Piece("red")

    def get_piece(self, position):
        return self._pieces.get(position)

    def move_piece(self, from_pos, to_pos):
        piece = self._pieces.pop(from_pos)
        piece.king_if_needed(to_pos[0])
        self._pieces[to_pos] = piece

    def draw_board(self):
        for row in range(8):
            for col in range(8):
                position = (row, col)
                piece = self.get_piece(position)
                if piece:
                    print(piece.symbol(), end="")
                else:
                    print(". ", end="")
            print()

class Piece:
    def __init__(self, color):
        self._color = color
        self._is_king = False

    def color(self):
        return self._color

    def king_if_needed(self, row):
        if self._color == "black" and row == 0 or self._color == "red" and row == 7:
            self._is_king = True

    def symbol(self):
        if self._is_king:
            return "K" if self._color == "black" else "R"
        return "k" if self._color == "black" else "r"

    def is_king(self):
        return self._is_king
```

